def fib(n: int) -> int:
    """
    Return the nth Fibonacci number (0-indexed) using naive recursion.

    Inefficiency note: this approach recomputes the same subproblems many times,
    leading to exponential time complexity (~O(2^n)) and deep recursion for large n.
    """
    if n < 0:
        raise ValueError("n must be non-negative")
    if n < 2:
        return n
    return fib(n - 1) + fib(n - 2)
